    private func generateSecureKey() throws -> Data {
        var keyData = Data(count: keySize)
        let result = keyData.withUnsafeMutableBytes { mutableBytes in
            guard let baseAddress = mutableBytes.baseAddress else { return errSecParam }
            return SecRandomCopyBytes(kSecRandomDefault, keySize, baseAddress)
        }
        
        guard result == errSecSuccess else {
            throw DataSecurityError.keyGenerationFailed
        }
        
